# Task: Improve Storage Error Handling

## Objective

Add startup validation for storage configuration and improve error messages so developers/admins know exactly what's missing.

## Implementation

### 1. Add Validation Function to `storage.ts`

```typescript
// src/lib/storage.ts

export interface StorageConfigStatus {
  valid: boolean
  configured: boolean
  missing: string[]
  warnings: string[]
}

export function validateStorageConfig(): StorageConfigStatus {
  const required = ['STORAGE_BUCKET']
  const credentials = ['AWS_ACCESS_KEY_ID', 'AWS_SECRET_ACCESS_KEY']

  const missing = required.filter(v => !process.env[v])
  const warnings: string[] = []

  // Check credentials (needed for real S3, not for some local setups)
  if (!process.env.STORAGE_ENDPOINT) {
    // Using real S3, credentials are required
    const missingCreds = credentials.filter(v => !process.env[v])
    if (missingCreds.length > 0) {
      warnings.push(`AWS credentials missing: ${missingCreds.join(', ')}`)
    }
  }

  return {
    valid: missing.length === 0,
    configured: missing.length === 0 && warnings.length === 0,
    missing,
    warnings
  }
}
```

### 2. Add Dev Server Warning

In `src/lib/storage.ts` (top-level):
```typescript
if (process.env.NODE_ENV === 'development') {
  const status = validateStorageConfig()
  if (!status.valid) {
    console.warn(
      '\n⚠️  Storage configuration incomplete!\n' +
      `   Missing: ${status.missing.join(', ')}\n` +
      '   Resume uploads will fail.\n' +
      '   See README.md for setup instructions.\n'
    )
  } else if (status.warnings.length > 0) {
    console.warn(
      '\n⚠️  Storage configuration warnings:\n' +
      status.warnings.map(w => `   - ${w}`).join('\n') + '\n'
    )
  }
}
```

### 3. Improve API Error Response

In `src/app/api/upload/resume/route.ts`:
```typescript
export async function POST(request: Request) {
  try {
    // ... existing code
    const { uploadUrl, publicUrl } = await generateUploadUrl(key, contentType)
    return NextResponse.json({ uploadUrl, publicUrl })
  } catch (error) {
    console.error('Upload URL generation failed:', error)

    // Provide specific error for config issues
    if (error instanceof Error) {
      if (error.message.includes('STORAGE_BUCKET')) {
        return NextResponse.json(
          { 
            error: 'Storage service not configured',
            code: 'STORAGE_NOT_CONFIGURED',
            details: process.env.NODE_ENV === 'development' 
              ? 'STORAGE_BUCKET environment variable is missing'
              : undefined
          },
          { status: 503 }
        )
      }
      if (error.message.includes('credentials') || error.message.includes('Access Denied')) {
        return NextResponse.json(
          { 
            error: 'Storage credentials invalid',
            code: 'STORAGE_AUTH_FAILED'
          },
          { status: 503 }
        )
      }
    }

    return NextResponse.json(
      { error: 'Failed to generate upload URL' },
      { status: 500 }
    )
  }
}
```

### 4. Frontend Error Handling

In `src/components/ui/resume-upload.tsx`:
```typescript
const handleUploadError = (error: unknown) => {
  if (error instanceof Error) {
    const response = JSON.parse(error.message) // If error contains JSON

    if (response.code === 'STORAGE_NOT_CONFIGURED') {
      toast.error('Resume uploads are not available. Contact your administrator.')
      return
    }
    if (response.code === 'STORAGE_AUTH_FAILED') {
      toast.error('Storage service authentication failed. Contact your administrator.')
      return
    }
  }

  toast.error('Failed to upload resume. Please try again.')
}
```

## Testing

1. Remove STORAGE_BUCKET from env → verify warning on dev server start
2. Attempt upload → verify specific error message in console and UI
3. Add config back → verify upload works

## Acceptance Criteria

- [ ] Dev server shows warning if storage not configured
- [ ] API returns specific error codes for config issues
- [ ] Frontend shows user-friendly messages
- [ ] Production doesn't leak sensitive config details

# Task: Integration Tests for Storage Config

## Objective

Add integration tests that verify storage configuration validation works correctly, without mocking the configuration check.

## Test File

`__tests__/integration/storage-config.test.ts`

## Test Cases

### 1. Validation Function Tests
```typescript
describe('validateStorageConfig', () => {
  const originalEnv = process.env

  beforeEach(() => {
    process.env = { ...originalEnv }
  })

  afterAll(() => {
    process.env = originalEnv
  })

  it('returns invalid when STORAGE_BUCKET is missing', () => {
    delete process.env.STORAGE_BUCKET

    const status = validateStorageConfig()

    expect(status.valid).toBe(false)
    expect(status.missing).toContain('STORAGE_BUCKET')
  })

  it('returns valid when STORAGE_BUCKET is set', () => {
    process.env.STORAGE_BUCKET = 'test-bucket'

    const status = validateStorageConfig()

    expect(status.valid).toBe(true)
    expect(status.missing).toHaveLength(0)
  })

  it('warns about missing credentials for non-local endpoint', () => {
    process.env.STORAGE_BUCKET = 'test-bucket'
    delete process.env.STORAGE_ENDPOINT
    delete process.env.AWS_ACCESS_KEY_ID

    const status = validateStorageConfig()

    expect(status.valid).toBe(true)  // Still valid
    expect(status.warnings.length).toBeGreaterThan(0)
    expect(status.warnings[0]).toContain('AWS_ACCESS_KEY_ID')
  })

  it('does not warn about credentials when using local endpoint', () => {
    process.env.STORAGE_BUCKET = 'test-bucket'
    process.env.STORAGE_ENDPOINT = 'http://localhost:9000'
    delete process.env.AWS_ACCESS_KEY_ID

    const status = validateStorageConfig()

    expect(status.valid).toBe(true)
    expect(status.warnings).toHaveLength(0)
  })
})
```

