  logResponse(status: number, body: unknown) {...}
  logDatabaseState(table: string, rows: unknown[]) {...}
  logAssertion(expected: unknown, actual: unknown) {...}

  finish() {
    this.log('TEST END', { 
      totalSteps: this.steps.length,
      passedSteps: this.steps.filter(s => s.status === 'pass').length
    })
    this.writeReport()
  }
}
